import { Handle, Position } from 'reactflow';

export const BaseNode = ({ id, label, children, handles = [] }) => {
  return (
    <div style={{ width: 200, border: '1px solid #333', borderRadius: '8px', padding: '10px', background: '#fff' }}>
      <div style={{ fontWeight: 'bold', marginBottom: '8px' }}>{label}</div>
      <div style={{ marginBottom: '8px' }}>{children}</div>
      
      {handles.map((h, index) => (
        <Handle
          key={index}
          type={h.type}
          position={h.position}
          id={`${id}-${h.id}`}
          style={{ top: h.top, background: '#555' }}
        />
      ))}
    </div>
  );
};
